mapper.sql:
SELECT
A.USERNM , C.SBJCT_ID , C.SBJCTNM , C.DVCLAS_NO
, (SELECT CNTCT FROM TB_LMS_USER_CNTCT WHERE USER_CNTCT_ID = C.PROF_USER_ID) AS MOBILE_NO , (SELECT USER_EML FROM TB_LMS_USER_CNTCT WHERE USER_CNTCT_ID = C.PROF_USER_ID) AS EMAIL , C.PROF_USER_ID , (SELECT USERNM FROM TB_LMS_USER_PRFIL WHERE USER_PRFIL_ID = C.PROF_USER_ID) AS PROF_USER_NM , C.TUTOR_USER_ID , C.TUTOR_USER_NM , A.EXAM_SPRT_APLY_TYCD
, B.GDSC_DGRS_CRS_GBNCD
FROM TB_LMS_USER_PRFIL A JOIN TB_LMS_ATNDLC_SBJCT B ON A.USER_PRFIL_ID = B.USER_ID
AND B.STD_ID = #{stdId}
JOIN ( SELECT AA.SBJCT_ID , MAX(AA.SBJCTNM) AS SBJCTNM , MAX(AA.DVCLAS_NO) AS DVCLAS_NO
, MAX(EE.USER_ID) AS PROF_USER_ID , (SELECT MAX(BB.USER_ID) AS TUTOR_USER_ID FROM TB_LMS_SBJCT AA LEFT JOIN ( SELECT SBJCT_ID, USER_ID FROM ( SELECT SBJCT_ID, USER_ID, ROW_NUMBER() OVER (PARTITION BY SBJCT_ID ORDER BY REG_DTTM DESC) AS RN FROM TB_LMS_SBJCT_PROF WHERE PROF_TYCD = 'ASSISTANT' ) WHERE RN = 1 ) BB ON AA.SBJCT_ID = BB.SBJCT_ID) AS TUTOR_USER_ID , (SELECT MAX(AA.USERNM) FROM TB_LMS_USER_PRFIL AA LEFT JOIN ( SELECT USER_ID FROM ( SELECT USER_ID, ROW_NUMBER() OVER (PARTITION BY SBJCT_ID ORDER BY REG_DTTM DESC) AS RN FROM TB_LMS_SBJCT_PROF WHERE PROF_TYCD = 'ASSISTANT' ) WHERE RN = 1 ) BB ON AA.USER_PRFIL_ID = BB.USER_ID) AS TUTOR_USER_NM FROM TB_LMS_SBJCT AA JOIN TB_LMS_SBJCT_PROF BB ON AA.SBJCT_ID = BB.SBJCT_ID
LEFT JOIN TB_LMS_EXAM_BSC CC ON BB.SBJCT_ID = CC.SBJCT_ID AND CC.DELYN = 'N' AND CC.EXAM_CTGRCD = 'EXAM' AND CC.EXAM_TYCD = 'EXAM'
LEFT JOIN TB_LMS_EXAM_BSC DD ON BB.SBJCT_ID = DD.SBJCT_ID AND DD.DELYN = 'N' AND DD.EXAM_CTGRCD = 'EXAM' AND DD.EXAM_TYCD = 'EXAM'
LEFT JOIN TB_LMS_SBJCT_PROF EE ON AA.SBJCT_ID = EE.SBJCT_ID AND EE.PROF_TYCD = 'PROFESSOR' AND EE.RPRSYN = 'Y' WHERE AA.DELYN = 'N' AND AA.SBJCT_TYCD = 'UNI'
AND AA.SBJCT_ID = #{creYear}
AND AA.CRS_ID = #{creTerm}
AND AA.CRS_ID NOT LIKE '%TEST%'
AND AA.UNIV_CD = #{uniCd}
AND AA.UNIV_GBNCD = #{univGbn}
AND AA.SBJCT_ID = #{crsCreCd}
AND EXISTS ( SELECT 1 FROM TB_LMS_SBJCT_PROF WHERE SBJCT_ID = AA.SBJCT_ID AND PROF_TYCD != 'MONITORING' AND USER_ID = #{searchFrom} )
GROUP BY AA.SBJCT_ID ) C ON B.SBJCT_ID = C.SBJCT_ID
WHERE A.ORG_ID = #{orgId}
AND A.DEPT_CD = #{deptCd}
AND A.USER_ID = #{userId}
AND LOWER(A.USERNM) LIKE '%' || LOWER(#{userNm}) || '%'
AND C.SBJCT_ID IN (SELECT SBJCT_ID FROM TB_LMS_SBJCT_PROF WHERE USER_ID = #{profUserId} AND PROF_TYCD <> 'MONITORING')
AND C.SBJCT_ID IN (SELECT SBJCT_ID FROM SBJCT_PROF WHERE LOWER((SELECT USERNM FROM TB_LMS_USR WHERE USER_ID = SBJCT_PROF.USER_ID)) LIKE '%' || LOWER(#{profUserNm}) || '%' AND PROF_TYCD <> 'MONITORING')
AND ( D.MID_APPR_STAT IS NULL OR D.MID_APPR_STAT NOT IN ('APPROVE', 'COMPANION') OR A.EXAM_SPRT_APLY_TYCD = 'N' )
AND D.MID_APPR_STAT IN ('APPROVE', 'COMPANION') AND A.EXAM_SPRT_APLY_TYCD = 'Y'
AND C.MID_EXAM_YN = 'Y'
AND C.LAST_EXAM_YN = 'Y'

mapper.select:
/* SQL ID : ExamDsblReqDAO.list 설 명 : 장애 지원 신청 리스트 조회 */ SELECT
A.* FROM (
) A WHERE 1=1
AND ( LOWER(A.DEPTNM) LIKE FN_LIKE_VAL(LOWER(#{searchValue})) OR LOWER(A.USER_ID) LIKE FN_LIKE_VAL(LOWER(#{searchValue})) OR LOWER(A.USERNM) LIKE FN_LIKE_VAL(LOWER(#{searchValue})) )

/* SQL ID : ExamDsblReqDAO.listExamDsblReqByAdmin 설 명 : 장애 지원 신청 리스트 조회 ( 관리자 ) */ SELECT ROW_NUMBER() OVER(ORDER BY CASE WHEN A.MID_APPR_STAT IS NOT NULL THEN 0 ELSE 1 END, A.SBJCTNM, A.DVCLAS_NO, A.USERNM) AS LINE_NO , A.* FROM (
AND ( LOWER(C.SBJCTNM) LIKE FN_LIKE_VAL(LOWER(#{searchValue})) OR LOWER(C.CRS_ID) LIKE FN_LIKE_VAL(LOWER(#{searchValue})) )
) A

/* SQL ID : ExamDsblReqDAO.select 설 명 : 장애 지원 신청 정보 조회 */ SELECT A.EXAM_SPRT_APLY_ID , A.SBJCT_ID , A.STD_ID , A.MID_APPR_STAT , A.MID_ADD_TIME , A.APRV_STSCD , A.ADD_MNTS , A.RGTR_ID , A.FRST_INQ_DTTM , A.MDFR_ID , A.MOD_DTTM , C.DEPTNM , C.USER_ID , C.USERNM , D.SBJCTNM , D.DVCLAS_NO , (SELECT CDNM FROM TB_ORG_CODE WHERE ORG_ID = C.ORG_ID AND CTGRCD = 'MN_DSBL_CD' AND CD = C.MN_DSBL_CD) AS DISABILITY_CD_NM , C.MN_DSBL_GRDCD , NVL((SELECT CDNM FROM TB_ORG_CODE WHERE ORG_ID = C.ORG_ID AND CTGRCD = 'MN_DSBL_GRDCD' AND CD = C.MN_DSBL_GRDCD), '기타') AS DISABILITY_LV_NM FROM TB_LMS_EXAM_SPRT_APLY A JOIN TB_LMS_ATNDLC_SBJCT B ON A.STD_ID = B.STD_ID AND A.SBJCT_ID = B.SBJCT_ID AND B.ATNDLC_STSCD = 'S' AND B.AUDITYN = 'N' JOIN TB_LMS_USR C ON B.USER_ID = C.USER_ID JOIN TB_LMS_SBJCT D ON A.SBJCT_ID = D.SBJCT_ID AND D.DELYN = 'N' WHERE 1 = 1
AND A.EXAM_SPRT_APLY_ID = #{dsblReqCd}
AND B.STD_ID = #{stdId}
AND A.SBJCT_ID = #{crsCreCd}

/* SQL ID : ExamDsblReqDAO.listMyCreCrsExamDsblReq 설 명 : 내 강의에 등록된 장애 시험 지원 리스트 조회 */ SELECT Z.* , ROW_NUMBER() OVER(ORDER BY Z.SBJCT_ID) AS lineNo FROM ( SELECT A.SBJCT_ID , A.SBJCTNM , A.DVCLAS_NO , B.STD_ID , D.MID_APPR_STAT , D.MID_ADD_TIME , D.ADD_MNTS , D.MOD_DTTM , (SELECT EXAM_SPRT_APLY_TYCD FROM TB_LMS_USR WHERE USER_ID = B.USER_ID) AS EXAM_SPRT_APLY_TYCD , (SELECT DISABILITY_CANCEL_GBN FROM TB_LMS_USR WHERE USER_ID = B.USER_ID) AS DISABILITY_CANCEL_GBN , COUNT(1) OVER() AS TOTAL_CNT , CASE WHEN EXISTS( SELECT 1 FROM TB_LMS_SYSJOB_SCHDL WHERE SYSJOB_SCHDL_TYCD = '00190805' AND DGRS_YR = A.SBJCT_ID AND DGRS_SMSTR = A.CRS_ID AND USEYN = 'Y' AND FN_DTTM() >= SYSJOB_SCHDL_SYMD ) THEN 'Y' ELSE 'N' END AS DSBL_REQ_DT_YN , CASE WHEN EXISTS( SELECT 1 FROM TB_LMS_SYSJOB_SCHDL WHERE SYSJOB_SCHDL_TYCD = '00190809' AND DGRS_YR = A.SBJCT_ID AND DGRS_SMSTR = A.CRS_ID AND USEYN = 'Y' AND FN_DTTM() >= SYSJOB_SCHDL_SYMD ) THEN 'Y' ELSE 'N' END AS DSBL_CONFIRM_DT_YN , (SELECT FRST_INQ_DTTM FROM TB_LOG_LESSON_ACTN_HSTY WHERE SBJCT_ID = 'DSBLREQ' AND USER_ID = B.USER_ID AND ACTV_HSTRY_CD = 'EXAM') AS FRST_INQ_DTTM -- ORDER BY FRST_INQ_DTTM DESC LIMIT 1 , NVL(( SELECT 'Y' FROM TB_LMS_EXAM_BSC WHERE EXAM_ID IN ( SELECT EXAM_ID FROM TB_LMS_EXAM_CRE_CRS_RLTN WHERE SBJCT_ID = A.SBJCT_ID AND DELYN = 'N' ) AND EXAM_CTGRCD = 'EXAM' AND EXAM_TYCD = 'EXAM' AND TKEXAM_TYCD = 'M' AND EXISTS(SELECT 1 FROM TB_LMS_STD_SCORE_ITEM_CONF WHERE MRK_TYCD = 'MIDDLE_TEST' AND MRK_RFLTRT >0 AND SBJCT_ID = A.SBJCT_ID) ), 'N') AS MID_EXAM_YN , NVL(( SELECT 'Y' FROM TB_LMS_EXAM_BSC WHERE EXAM_ID IN ( SELECT EXAM_ID FROM TB_LMS_EXAM_CRE_CRS_RLTN WHERE SBJCT_ID = A.SBJCT_ID AND DELYN = 'N' ) AND EXAM_CTGRCD = 'EXAM' AND EXAM_TYCD = 'EXAM' AND TKEXAM_TYCD = 'L' AND EXISTS(SELECT 1 FROM TB_LMS_STD_SCORE_ITEM_CONF WHERE MRK_TYCD = 'LAST_TEST' AND MRK_RFLTRT >0 AND SBJCT_ID = A.SBJCT_ID) ), 'N') AS LAST_EXAM_YN , D.EXTDTM_CHGYN FROM TB_LMS_SBJCT A JOIN TB_LMS_ATNDLC_SBJCT B ON A.SBJCT_ID = B.SBJCT_ID AND B.ATNDLC_STSCD = 'S' AND A.DELYN = 'N' JOIN TB_LMS_USR C ON B.USER_ID = C.USER_ID AND C.DISABLILITY_YN = 'Y' LEFT JOIN TB_LMS_EXAM_SPRT_APLY D ON B.STD_ID = D.STD_ID AND A.SBJCT_ID = D.SBJCT_ID WHERE B.USER_ID = #{userId}
AND A.SBJCT_ID = #{creYear}
AND A.CRS_ID = #{creTerm}
AND A.SBJCT_ID = #{crsCreCd}
AND LOWER(A.SBJCTNM) LIKE FN_LIKE_VAL(LOWER(#{searchValue}))
) Z WHERE (Z.MID_EXAM_YN = 'Y' OR Z.LAST_EXAM_YN = 'Y')

mapper.insert:
		/*
             SQL ID : ExamDsblReqDAO.insertExamDsblReq
            	 설  명 : 장애인 지원 신청
         */
    	INSERT INTO TB_LMS_EXAM_SPRT_APLY (
    		  EXAM_SPRT_APLY_ID
			, SBJCT_ID
			, STD_ID
			, MID_APPR_STAT
			, MID_ADD_TIME
			, APRV_STSCD
			, ADD_MNTS

			, EXTDTM_CHGYN

			, RGTR_ID
			, FRST_INQ_DTTM
			, MDFR_ID
			, MOD_DTTM
    	) VALUES (
    		  #{dsblReqCd}
    		, #{crsCreCd}
    		, #{stdId}
    		, #{midApprStat}
    		, #{midAddTime}
    		, #{endApprStat}
    		, #{endAddTime}

			, #{profEditYn}

    		, #{rgtrId}
    		, FN_DTTM()
    		, #{mdfrId}
    		, FN_DTTM()
    	)

mapper.update:
		/*
             SQL ID : ExamDsblReqDAO.updateExamDsblReq
            	 설  명 : 장애인 지원 신청 수정
         */
		UPDATE TB_LMS_EXAM_SPRT_APLY SET
			  MDFR_ID 		= #{mdfrId}
			, MOD_DTTM 		= FN_DTTM()
			, MID_APPR_STAT = #{midApprStat}
			, MID_ADD_TIME 	= #{midAddTime}
			, APRV_STSCD = #{endApprStat}
			, ADD_MNTS 	= #{endAddTime}

			, EXTDTM_CHGYN  = #{profEditYn}

		WHERE EXAM_SPRT_APLY_ID = #{dsblReqCd}

/* SQL ID : ExamDsblReqDAO.updateExamDsblReqByModDttm 설 명 : 장애인 지원 신청 수정일시 수정 */ UPDATE TB_LMS_EXAM_SPRT_APLY SET MOD_DTTM = FN_DTTM()
, MID_ADD_TIME = 0 , ADD_MNTS = 0
WHERE RGTR_ID = #{userId}
